public int caughtSpeeding(int speed, boolean isBirthday) {
    int baseLimit = 60;
    int smallLimit = 80;
    int bigLimit = 81;

    if (isBirthday) {
        baseLimit += 5;
        smallLimit += 5;
    }

    if (speed <= baseLimit) {
        return 0;
    } else if (speed <= smallLimit) {
        return 1;
    } else {
        return 2;
    }
}

public int roundSum(int a, int b, int c) {
    a = round10(a);
    b = round10(b);
    c = round10(c);
    return a + b + c;
}

public int round10(int num) {
    int lastDigit = num % 10;
    if (lastDigit >= 5) {
        num += 10 - lastDigit;
    } else {
        num -= lastDigit;
    }
    return num - num % 10;
}

